// Process raw data into FamilyMember array
export const familyMembers: FamilyMember[] = rawData.map((r) => {
  const birthYear = extractYear(r.birthDate);
  const deathYear = r.deathDate ? extractYear(r.deathDate) : undefined;
  const childrenNames = r.children
    ? r.children.split(";").map((c) => c.trim()).filter(Boolean)
    : [];

  return {
    id: `${r.pageId}-${r.personId}`,
    pageId: r.pageId as FamilyMember["pageId"],
    commonName: r.commonName,
    firstName: r.firstName,
    middleName: r.middleName || undefined,
    lastName: r.lastName,
    birthDate: r.birthDate,
    birthYear,
    birthPlace: r.birthPlace || undefined,
    baptismDate: r.baptismDate || undefined,
    baptismPlace: r.baptismPlace || undefined,
    deathDate: r.deathDate || undefined,
    deathYear: deathYear || undefined,
    deathPlace: r.deathPlace || undefined,
    gender: inferGender(r.firstName, r.commonName),
    spouseName: r.spouseName || undefined,
    marriageDate: r.marriageDate || undefined,
    marriagePlace: r.marriagePlace || undefined,
    childrenNames,
    parent1Name: r.parent1 || undefined,
    parent2Name: r.parent2 || undefined,
  };
});

// Group by era
export interface Era {
  label: string;
  range: [number, number];
  members: FamilyMember[];
}

export function getEras(members: FamilyMember[]): Era[] {
  const eras: Era[] = [
    { label: "1700s", range: [1700, 1799], members: [] },
    { label: "1800s", range: [1800, 1899], members: [] },
    { label: "1900s", range: [1900, 1999], members: [] },
    { label: "2000s", range: [2000, 2099], members: [] },
  ];
  members.forEach((m) => {
    const era = eras.find((e) => m.birthYear >= e.range[0] && m.birthYear <= e.range[1]);
    if (era) era.members.push(m);
  });
  return eras.filter((e) => e.members.length > 0);
}

// Get family branches (by page)
export function getBranches(members: FamilyMember[]): { label: string; pageId: string; rootMember: FamilyMember }[] {
  const pages = ["p1", "p2", "p3", "p4"];
  const labels = [
    "Henderson / Sowerby / Chilton Branch",
    "Moses / Mosey Branch",
    "Ainsley / Smailes / Stiff Branch",
    "Haddock / Stones Branch",
  ];
  return pages.map((pageId, i) => {
    const branchMembers = members.filter((m) => m.pageId === pageId);
    return {
      label: labels[i],
      pageId,
      rootMember: branchMembers[0],
    };
  });
}

// Get members by page
export function getMembersByBranch(members: FamilyMember[], pageId: string): FamilyMember[] {
  return members.filter((m) => m.pageId === pageId);
}
